  const [isLoading, setIsLoading] = useState(false);
  const handleRefresh = () => {
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
    }, 1000);
  };
  return <Comments {...argTypes} isLoading={isLoading} handleRefresh={handleRefresh}>
      <Comments.Item>
        <Comments.Header>
          <Comments.Author />
          <Comments.Meta />
        </Comments.Header>
        <Comments.Content />
        <Comments.Actions />
      </Comments.Item>
    </Comments>;
